(()=>{"use strict";window.onload=function(){setInterval((()=>{e(),t(),n()}),1e3),r()};const e=()=>{const e=document.querySelector(".clock"),t=new Date,n=String(t.getHours()).padStart(2,"0"),r=String(t.getMinutes()).padStart(2,"0"),a=String(t.getSeconds()).padStart(2,"0");e.innerText=`${n}:${r}:${a}`},t=()=>{const e=document.querySelector(".calendar"),t=new Date,n=String(t.getFullYear()),r=t.getMonth(),a=String(t.getDate()),o=t.getDay();e.innerText=`${["Sunday","Monday","Tuesday","Wednesday","Thursday","Friday","Saturday"][o]}, ${["January","February","March","April","May","June","July","August","September","October","November","December"][r]} ${a}, ${n}`},n=()=>{const e=document.querySelector(".greeting");let t="";switch(Math.floor((new Date).getHours()/6)){case 0:t="night";break;case 1:t="morning";break;case 2:t="afternoon";break;case 3:t="evening"}e.innerText=`Good ${t}, `},r=()=>{}})();